// Works with dead-man-switch / uptime services (Healthchecks.io, UptimeRobot, etc.)
const b = ($input.first().json.body) || $input.first().json || {};
const typeRaw = String(b.alertType != null ? b.alertType : (b.alertTypeFriendlyName || b.status || '')).toLowerCase();
const isDown = typeRaw === '1' || typeRaw.includes('down') || typeRaw.includes('fail');
const icon = isDown ? '\uD83D\uDD34' : '\uD83D\uDFE2';
const state = isDown ? 'DOWN' : 'UP';
const monitor = b.monitor || b.monitorFriendlyName || b.name || '?';
const url = b.url || b.monitorURL || '?';
const details = b.details || b.alertDetails || '\u2014';
const dt = b.datetime || b.alertDateTime || '';
const msg = icon + ' *VertiGuard external \u2014 ' + state + '*\n' +
  '\u2022 Monitor: ' + monitor + '\n' +
  '\u2022 URL: ' + url + '\n' +
  '\u2022 Detail: ' + details + '\n' +
  (dt ? ('\uD83D\uDD52 ' + dt) : '');
return [{ json: { message: msg } }];
